# NL DHA.  Den Helder - Amsterdam Centraal
#
let da = path("d3.nl.dha");

with detail = 3,
     railway = :first :cat:dc15 :pax
{
    with link = "point.nl.Den-Helder" {
        track(da[:den.f, :den.f + 0.5sw]);
        marker(:bottom :de.bf, da[:den.f]);
        slabel(:top :bold, da[:den.f - 1sh] + (0dt, -0.3dt),
            "Den Helder"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:den.f + 0.49sw, :dez - 0.49sw]);
    }

    with link = "point.nl.Den-Helder-Zuid" {
        track(da[:dez - 0.5sw, :dez + 0.5sw]);
        marker(:left :de.bf, da[:dez] << 0.5mt);
        slabel(:right, da[:dez] << 0.5mt << 1.sh + (1.3dt, 0.9dt),
            "Den Helder Zuid"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:dez + 0.49sw, :dez + 1.51km]);
        line_label(:right:e, da[:dez + 1.5km] >> 0.5mt, (0dt, 0.1dt), "DHA");
        track(da[:dez + 1.49km, :koe - 0.49sw]);
    }

    with link = "point.nl.Koegras" {
        track(da[:koe - 0.5sw, :koe + 0.5sw]);
        marker(:right :de.hp :removed, da[:koe] >> 0.5mt);
        slabel(:left :removed, da[:koe] >> 0.5mt >> 1sh + (-1.5dt, 1.5dt),
            "Koegras"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:koe + 0.49sw, :bre - 0.49sw]);
    }

    with link = "point.nl.Breezand" {
        track(da[:bre - 0.5sw, :bre + 0.5sw]);
        marker(:right :de.hp :removed, da[:bre] >> 0.5mt);
        slabel(:left :removed, da[:bre] >> 0.5mt >> 1sh + (-1.3dt, 1.2dt),
            "Breezand"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:bre + 0.49sw, :ann - 0.49sw]);
    }

    with link = "point.nl.Anna-Paulowna" {
        track(da[:ann - 0.5sw, :ann + 0.5sw]);
        marker(:left :de.bf, da[:ann] << 0.5mt);
        slabel(:right, da[:ann] << 0.5mt << 1.sh + (1.5dt, 1.2dt),
            "Anna Paulowna"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:ann + 0.49sw, :osl - 0.49sw]);
    }

    with link = "point.nl.Oudesluis" {
        track(da[:osl - 0.5sw, :osl + 0.5sw]);
        marker(:right :de.hp :removed, da[:osl] >> 0.5mt);
        slabel(:left :removed, da[:osl] >> 0.5mt >> 1sh + (-1.3dt, 0.8dt),
            "Oudesluis"
        );
    }

    with link = "line.nl.DHA" {
        track(
                da[:osl + 0.49sw, :osl + 0.5sw]
            ..  da[:osl.xs + 1md, :sag - 0.49sw] >> 0.5md << 0.5mt
        );
    }
}

with detail = 3,
     railway = :first :double :cat:dc15 :pax
{
    with link = "point.nl.Schagen" {
        track(da[:sag - 0.5sw, :sag + 0.5sw]);
        marker(:right :de.bf, da[:sag] >> 0.5md);
        slabel(:left, da[:sag] >> 0.5md >> 1sh + (-1.4dt, 1dt),
            "Schagen"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:sag + 0.49sw, :saw - 0.49sw]);
    }

    with link = "point.nl.Schagerwaard" {
        track(da[:saw - 0.5sw, :saw + 0.5sw]);
        marker(:right :de.hp :removed, da[:saw] >> 0.5md);
        slabel(:left :removed, da[:saw] >> 0.5md >> 1sh + (-1.5dt, 1dt),
            "Schagerwaard"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:saw + 0.49sw, :zij - 0.49sw]);
    }

    with link = "point.nl.Zijdewind" {
        track(da[:zij - 0.5sw, :zij + 0.5sw]);
        marker(:right :de.hp :removed, da[:zij] >> 0.5md);
        slabel(:left :removed, da[:zij] >> 0.5md >> 1sh + (-1.5dt, 1.3dt),
            "Zijdewind"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:zij + 0.49sw, :nsc - 0.49sw]);
    }

    with link = "point.nl.Noord-Scharwoude" {
        track(da[:nsc - 0.5sw, :nsc + 0.5sw]);
        marker(:left :de.bf :removed, da[:nsc] << 0.5md);
        slabel(:right :removed, da[:nsc] << 0.5md << 1sh + (1.4dt, 1.2dt),
            "Noord Scharwoude"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:nsc + 0.49sw, :nsc + 1.61km]);
        line_label(:right:e, da[:nsc + 1.6km] >> 0.5md, "DHA");
        track(da[:nsc + 1.59km, :her.yh - 0.99seg]);
    }

    with link = "point.nl.Heerhugowaard" {
        track(da[:her.yh - 1seg, :her + 0.5sw]);
        marker(:right :de.bf, da[:her] >> 0.5md);
        slabel(:left :bold, da[:her + 0.5sw] >> 0.5md >> 1.3sh,
            "Heerhugowaard"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:her + 0.5sw, :kak - 0.3sw]);
    }

    with link = "point.nl.Kanaal-Alkmaar-Kolhorn" {
        track(da[:kak - 0.3sw, :kak + 0.3sw]);
        marker(:right :de.dkst, da[:kak] >> 0.5md);
    }

    with link = "line.nl.DHA" {
        track(da[:kak + 0.3sw, :pan - 0.5sw]);
    }

    with link = "point.nl.St-Pancras" {
        track(da[:pan - 0.5sw, :pan + 0.5sw]);
        marker(:right :de.hp :removed, da[:pan] >> 0.5md);
        slabel(:left :removed, da[:pan + 0.5sw] >> 0.5md >> 1.3sh,
            "St. Pancras"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:pan + 0.5sw, :aln - 0.5sw]);
    }

    with link = "point.nl.Alkmaar-Noord" {
        track(da[:aln - 0.5sw, :aln + 0.5sw]);
        marker(:right :de.hp, da[:aln] >> 0.5md);
        slabel(:nw, da[:aln - 0.5sw] << 0.4md, "Alkmaar Noord");
    }

    with link = "line.nl.DHA" {
        track(da[:aln + 0.5sw, :nka - 0.3sw]);
    }

    with link = "point.nl.Noordhollands-kanaal" {
        track(da[:nka - 0.3sw, :nka + 0.3sw]);
        marker(:left :de.dkst, da[:nka] << 0.5md);
    }

    with link = "line.nl.DHA" {
        track(da[:nka + 0.3sw, :alk - 0.5sw]);
    }

    with link = "point.nl.Alkmaar" {
        track(da[:alk - 0.5sw, :alk + 0.5sw]);
        marker(:left :de.bf, da[:alk] << 0.5md);
        slabel(:left :bold, da[:alk - 0.7sw] >> 1md, "Alkmaar");
    }

    with link = "line.nl.DHA" {
        track(da[:alk + 0.5sw, :alk + 3km]);
        line_label(:right:e, da[:alk + 3km] >> 0.5md, (0dt, -0.3dt), "DHA");
        track(da[:alk + 3km, :hei - 0.5sw]);
    }

    with link = "point.nl.Heiloo" {
        track(da[:hei - 0.5sw, :hei + 0.5sw]);
        marker(:left :de.hp, da[:hei] << 0.5md);
        slabel(:right, da[:hei] << 0.5md << 1.6sh + (0dt, 0.8dt),
            "Heiloo"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:hei + 0.5sw, :olv - 0.5sw]);
    }

    with link = "point.nl.Onze-Lieve-Vrouwe-ter-Nood" {
        track(da[:olv - 0.5sw, :olv + 0.5sw]);
        marker(:left :de.hp :removed, da[:olv] << 0.5md);
        slabel(:left :removed, da[:olv] >> 1.0md + (0dt, 1dt),
            "Onze Lieve Vrouwe ter Nood*"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:olv + 0.5sw, :cas - 0.5sw]);
    }

    with link = "point.nl.Castricum" {
        track(da[:cas - 0.5sw, :cas + 0.5sw]);
        marker(:left :de.hp, da[:cas] << 0.5md);
        slabel(:left, da[:cas] >> 1.5md + (0dt, 0.3dt), "Castricum");
    }

    with link = "line.nl.DHA" {
        track(da[:cas + 0.5sw, :cas + 2km]);
        line_label(:right:ne, da[:cas + 2km] >> 0.5md, "DHA");
        track(da[:cas + 2km, :uit - 400m]);
    }

    with link = "point.nl.Uitgeest" {
        track(da[:uit - 400m, :uit.yh]);
        track(:single,
                da[:uit - 376m, :uit - 375m] >> 0.5md << 0.5mt
            --  da[:uit - 375m + 1dl, :uit.yh] >> 0.5md >> 1ms >> 0.5mt
        );
        marker(:left :de.bf, da[:uit] << 0.5md);
        slabel(:right :bold, da[:uit + 0.5sw] << 0.5md << 1.2sh, "Uitgeest");
    }

    with link = "line.nl.DHA" {
        track(da[:uit.yh, :uit.yh + 2km]);
        line_label(:left:sw, da[:uit.yh + 2km] << 0.5md, "DHA");
        track(da[:uit.yh + 2km, :kro.2008 - 0.3sw]);
    }

    with link = "point.nl.Krommenie-Assendelft" {
        track(da[:kro.2008 - 0.5sw, :kro + 0.5sw]);
        marker(:left :de.hp, da[:kro.2008] << 0.5md);
        marker(:left :de.bf :removed, da[:kro] << 0.5md);
        slabel(:ne, da[:kro] >> 0.5md,
            vbox(:right:top, "Krommenie-", "Assendelft ")
        );
    }

    with link = "line.nl.DHA" {
        track(da[:kro + 0.5sw, :nau - 0.3sw]);
    }

    with link = "point.nl.Nauernasche-vaartbrug" {
        track(da[:nau - 0.3sw, :nau + 0.3sw]);
        marker(:left :de.dkst, da[:nau] << 0.5md);
    }

    with link = "line.nl.DHA" {
        track(da[:nau + 0.3sw, :wor - 0.5sw]);
    }

    with link = "point.nl.Wormerveer" {
        track(da[:wor - 0.5sw, :wor + 0.5sw]);
        marker(:left :de.bf, da[:wor] << 0.5md);
        slabel(:right, da[:wor + 0.5sw] << 0.5md << 1.2sh,
            "Wormerveer"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:wor + 0.5sw, :wor + 1km]);
        line_label(:left:w, da[:wor + 1km] << 0.5md, (0dt, -0.2dt), "DHA");
        track(da[:wor + 1km, :zzs - 0.5sw]);
    }

    with link = "point.nl.Zaandijk-Zaanse-Schans" {
        track(da[:zzs - 0.5sw, :zzs + 0.5sw]);
        marker(:left :de.hp, da[:zzs] << 0.5md);
        slabel(:left, da[:zzs] >> 1.2md + (0dt, 0.9dt),
            "Zaandijk Zaanse Schans*"
        );
    }

    with link = "line.nl.DHA" {
        track(da[:zzs + 0.5sw, :kog - 0.5sw]);
    }

    with link = "point.nl.Koog-aan-de-Zaan" {
        track(da[:kog - 0.5sw, :kog + 0.5sw]);
        marker(:left :de.hp :casing, da[:kog] << 0.5md);
        slabel(:left, da[:kog] >> 1.2md + (0dt, 0.9dt), "Koog aan de Zaan*");
    }

    with link = "line.nl.DHA" {
        with layer = -1 track(da[:kog + 0.5sw, :zaa.ye]);
    }

    with link = "point.nl.Zaandam", railway = :station {
        let zs = path("d3.nl.zsg");

        # ZEH dn
        track(:single,
                da[:zaa.ye, :zaa] >> 0.5md >> 1ms >> 0.5mt
            ..  zs[:zaa.xa, :zaa.xa + 0.1dl] >> 1.5mt >> 2ms
        );

        # DHA
        track(da[:zaa.ye, :zaa]);

        # DHA up
        track(:single,
                da[:zaa.ye, :zaa] >> 0.5dst << 0.5mt
            ..  zs[:zaa.xa, :zaa.xa + 0.1dl] >> 0.5mt >> 0.5ms
        );

        # DHA dn
        track(:single,
                da[:zaa.ye, :zaa] << 0.5dst >> 0.5mt
            ..  zs[:zaa.xa, :zaa.xa + 0.1dl] >> 0.5mt >> 0.5ms
        );

        # ZEH up
        track(:single,
                da[:zaa.ye, :zaa] << 0.5md << 1ms << 0.5mt
            ..  zs[:zaa.xa, :zaa.xa + 0.1dl] << 0.5mt << 0.5ms
        );

        marker(:left :de.bf, da[:zaa] << 0.5md << 1ms << 0.5mt);
        slabel(:right :bold, da[:zaa] << 1.5mo << 1.4sh + (0dt, 0.6sw),
            "Zaandam"
        );
    }
}

with detail = 3,
     railway = :first :double :removed
{
    with link = "line.nl.DHA" {
        track(da[:zaa, :zaa.xa + 2dt]);
        line_label(:left:w, da[:zaa.xa + 2dt] << 0.5md, "DHA");
        track(
                da[:zaa.xa + 2dt, :zaa.xa + 2.1dt]
            ..  da[:awh.a, :awh.a + 0.1dl] << 1.5mt << 2ms << 0.5md
        );
    }
}

with detail = 3,
     railway = :first :cat:dc15 :nopax
{
    with link = "point.nl.Amsterdam-Westhaven" {
        track(:double,
                da[:awh.a, :awh + 0.5sw] << 1.5mt << 2ms << 0.5md
        );
        marker(:right:de.gbf, da[:awh] << 1mt << 2ms << 0.5md);
        slabel(:right, da[:awh + 0.5sw] << 1mt << 2ms << 1.7md,
            "A. Westhaven"
        );
    }
}

with detail = 3,
     railway = :first :cat:dc15 :nopax
{
    with link = "line.nl.DHA" {
        track(:double,
                da[:awh + 0.5sw, :sin.yr] << 1.5mt << 2ms << 0.5md
        );
        track(
                da[:sin.yr, :sin.yr + 1dl] << 1.5mt << 2ms << 0.5md
            ..  da[:sin - 1.5dl, :sin - 1dl] << 0.5md << 2.5mt << 3ms
        );
    }
}

with detail = 3,
     railway = :first :cat:dc15 :pax
{
    with link = "point.nl.Singelgracht" {
        track(         # nl.DHA
                da[:sin - 1.1dl, :sin - 1dl] << 0.5dst << 2.5st << 3ds
            --  da[:sin, :sib] << 0.5md << 1.5mt << 2ms
        );
        track(         # nl.ZSG links
                da[:sin - 1dl, :sib] << 0.5md << 1.5mt << 2ms
        );
        track(:double, # nl.ASR
                da[:sin - 1dl, :sib]
                       >> 0.5md << 1mt << 1ms << 0.5md
        );
        track(         # nl.ZSG rechts
                da[:sin - 1dl, :sib] >> 0.5md << 0.5mt
        );
        track(:double, # nl.ARD
                da[:sin - 1dl, :sib] >> 1md >> 1ms
        );

        marker(:left :de.abzw, da[:sin - 1dl] << 1md << 2.5mt << 3ms);
        slabel(:right :xsmall:bold,
            da[:sin - 1dl] << 1md << 2.5mt << 3ms << 1.4sh + (-1sw, 0dt),
            "Singelgracht aansl."
        );
    }

    with link = "point.nl.Singelgrachtbrug" {
        marker(:left :de.dkst, da[:sib] << 1md << 1.5mt << 2ms);
    }

    with link = "line.nl.DHA" {
        track(:single, # (nl.ZSG links)
                da[:sin + 1dl, :sin + 1.1dl] << 0.5dst << 1.5st << 2ds
            ..  da[:ams - 0.51sw, :ams - 0.5sw] << 1.5dst << 1ds >> 0.5st
        )
        track( # (nl.ASR links)
                da[:sin + 1dl, :sin + 1.1dl] << 0.5dst << 0.5st << 1ds
            ..  da[:ams - 0.51sw, :ams - 0.5sw] << 0.5dst << 1ds << 0.5st
        )
        track( # (nl.ASR rechts)
                da[:sin + 1dl, :sin + 1.1dl] >> 0.5dst << 1.5st << 1ds
            ..  da[:ams - 0.51sw, :ams - 0.5sw] << 0.5dst >> 0.5st
        );
        track( # (nl.ZSG rechts)
                da[:sin + 1dl, :sin + 1.1dl] >> 0.5dst << 0.5st
            ..  da[:ams - 0.51sw, :ams - 0.5sw] >> 0.5dst << 0.5st
        );
        track(:double, # (nl.ARD)
                da[:sin + 1dl, :sin + 1.1dl] >> 1dst >> 1ds
            ..  da[:ams - 0.51sw, :ams - 0.5sw] >> 1dst >> 1ds
        );
    }

    with link = "point.nl.Amsterdam-Centraal" {
        track(:double, da[:ams - 0.5sw, :ams + 300m] << 1md << 1ms);
        track(:double, da[:ams - 0.5sw, :ams + 300m]);
        track(:double, da[:ams - 0.5sw, :ams + 300m] >> 1md >> 1ms);
        marker(:right :de.bf, da[:ams] >> 1.5md >> 1ms);
        slabel(:left :bold, da[:ams - 0.8sw] >> 1.5md >> 1ms >> 1.5sh,
            "A. Centraal"
        );

        slabel(:right :large :bold, da[:ams] + (3km, 0dt), "Amsterdam");
    }
}

